export function Original (newPrice, secondPrice, card) { 
  var totalPrice = 0

  totalPrice = newPrice
  if (newPrice >= 50 && card) {
    //closed border
    totalPrice = newPrice * 0.85
  } else if (newPrice >= 50) {
    //closed border
    totalPrice = newPrice * 0.9
  } else if (card) {
    totalPrice = newPrice * 0.9
  }
  if (secondPrice > 60 && newPrice > 30) {
    totalPrice = totalPrice + secondPrice * 0.95
  } else totalPrice = totalPrice + secondPrice

  totalPrice = Math.round((totalPrice + Number.EPSILON) * 100) / 100
  return totalPrice
}

