import React, { useState, useRef } from 'react'

import './App.css'
import { array_of_mutants, Original } from './mutants'

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function App () {
  var [eredmeny, setEredmeny] = useState('-')
  var [killedMutants, setKilledMutants] = useState('-')
  var [testCaseNumber, setNumber] = useState(0)
  var [killed, setKilled] = useState([])
  //var [wrongTests, setWrongTests] = useState('')
  var [wrongTests] = useState([])
  var [printWrongTests, setPrintWrongTests] = useState('')
  var [missing, setMissing] = useState('')
  var [result, setResult] = useState('')
  var [mutant] = useState([])
  var [wrongSolution, setWrongSolution] = useState(false)

  var xInput = useRef()
  var yInput = useRef()
  var zInput = useRef()

  function init () {
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false
      mutant[i] = ''
    }
    setResult('')
    setMissing('')
    setNumber(0)
    setEredmeny(0)
    setWrongSolution(false)
    xInput.current.value = ''
    yInput.current.value = ''
    wrongTests[0] = ''
  }
 
  function callFunctions () {
    var x = +xInput.current.value
    var y = +yInput.current.value
    var z = zInput.current.checked
    var totalPrice = 0
    var killedMutants1 = ''
    var origPrice = Original(x, y, z)
    setEredmeny(origPrice)
    var superfluousTest = true
    if (!(x == 0 && y == 0 && z == 0)) {
      testCaseNumber++
      for (var i = 0; i < array_of_mutants.length; i++) {
        if (!killed[i]) {
          totalPrice = array_of_mutants[i](x, y, z).price
          mutant[i] = array_of_mutants[i](x, y, z).mutant
          if (origPrice != totalPrice) {
            var j = i + 1
            killedMutants1 = killedMutants1 + j + ' '
            killed[i] = true
            superfluousTest = false
          }
        }
      }
      if (superfluousTest) {
        wrongTests[0] =
          "This test case is superfluous as it will not find any BVA-reated bug that haven't been found by your previous tests!"
        wrongSolution = true
        console.log(' wrongSolution ' + wrongSolution)
        //     console.log(wrongTests[0], ' superfluous')
      } else wrongTests[0] = ''
      /*
      if (superfluousTest) {
        if (wrongTests == '') {
          wrongTests = 'Superfluous BVA tests: '
        }
        wrongTests = wrongTests + '#' + testCaseNumber + ' '
      }
      */
    }
    setWrongSolution(wrongSolution)
    setKilledMutants(killedMutants1)
    setNumber(testCaseNumber)

  //  setKilledMutants(killedMutants1)
  //  setNumber(testCaseNumber)
  //  setWrongTests(wrongTests)
  }

  function printResult () {
    var optimalTestCaseNumber = 10 //!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    var missingTests = false

    //callFunctions()
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = 'Your tests would fail for this bug: ' + mutant[i] 
        missingTests = true
        console.log('not killed new ', i)
      }
    }
    printWrongTests = wrongTests
    setPrintWrongTests(printWrongTests)
    console.log('wrong ' + wrongSolution)
    if (testCaseNumber === 0) {
      result = 'Please write your test cases!'
    } else if (
      !missingTests &&
      !wrongSolution &&
      testCaseNumber > optimalTestCaseNumber
    ) {
      result =
        'Congratulation, you are very good at test design! Our solution requires 10 test cases.'
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else if (!missingTests && !wrongSolution) {
      result = 'Congratulation, you are very good at test design!'
    } else result = ' Try again! '
    setResult(result)
    setMissing(missing)
  }

  return (
    <div className="App">
	  <header className="Back-header">
	  <p class="Back">
	    <a href="https://test-design.org/practical-exercises/">Back to Test Design Exercises</a>
	  </p>
	  </header>
	  
      <header className="App-header">
        
        <p class="exercise"> <b> Exercise. </b> Read the specification below carefully. Design and add
         your test cases one-by-one entering with "Next test case". <br/> After your last test, click on "Show my result".
         Apply single fault assumption and boundary value analysis for normal test design.  

        </p>
        <p class='specification'>
          {' '}
          <b>Online book store </b>
          <br />
          <b>R1</b> For online new book purchasing regular customers with cards obtain 10%
          price reduction. <br />
          <b>R2</b> Similarly, any customer buying new books for at least EUR 50 gets 10%
          price reduction. <br />
          <b>R3</b> If somebody has a card and buys new books not less than EUR 50, then
          the price reduction is 15%. <br />
          <b>R4</b> If a customer buys second hand books s/he gets price reduction 5%, but
          only if the price of them exceeds EUR 60 and s/he also buys new books
          for more than EUR 30. <br />
          <b>R5</b> The output is the price to be paid. Minimum price difference: 0.01
          euro. &nbsp;&nbsp;{' '}
        </p>

        <p class='testcases'>
          <span data-harmony-id='Missing test'> {missing}</span>{' '}
          <span data-harmony-id='result'>{result}</span> <br />
          <br />
          New book price:{' '}
          <input size='4' data-harmony-id='New price' ref={xInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Second hand book price:{' '}
          <input size='4' data-harmony-id='Second price' ref={yInput} />
          &nbsp;&nbsp;&nbsp;&nbsp; VIP customer:{' '}
          <input type='checkbox' data-harmony-id='Card' ref={zInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Total price:{' '}
          <span data-harmony-id='Total price'>{eredmeny}</span> <br /> <br />
          
          <span
            data-harmony-id='Test case number'
            style={{ color: 'mediumaquamarine' }}
          >
            Number of test cases: {testCaseNumber}
          </span>{' '}
          <br /> <br />
          <button
            class='button'
            data-harmony-id='Add test'
            onClick={callFunctions}
          >
            {' '}
            Add this test case{' '}
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class='button' data-harmony-id='Stop' onClick={printResult}>
            {' '}
            Show my result{' '}
          </button>{' '}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class='button' data-harmony-id='Try again' onClick={init}>
            {' '}
            Try again{' '}
          </button>{' '}
          <br />
         
        </p>
      </header>
    </div>
  )
}

export default App
